import { useState, useRef, useEffect, useMemo } from 'react';
import * as Popover from '@radix-ui/react-popover';

/* ───── Design tokens ───── */
const C = {
  bg: '#0B0F14',
  surface: '#0F1620',
  surface2: '#111A24',
  border: '#1F2A37',
  textPrimary: '#E5E7DB',
  textSecondary: '#90A3AF',
  green: '#22C55E',
  red: '#EF4444',
  blue: '#60A5FA',
  amber: '#F59E0B',
};
const mono = "'JetBrains Mono', monospace";
const body = "'Plus Jakarta Sans', sans-serif";

/* ───── Keyframe injection ───── */
const KEYFRAME_ID = '__sft-kf';
function ensureKeyframes() {
  if (typeof document === 'undefined') return;
  if (document.getElementById(KEYFRAME_ID)) return;
  const style = document.createElement('style');
  style.id = KEYFRAME_ID;
  style.textContent = `
    @keyframes sftPulse {
      0%, 100% { opacity: 0.25; }
      50%      { opacity: 0.4; }
    }
  `;
  document.head.appendChild(style);
}

/* ───── Filter icon SVG ───── */
function FilterIcon({ active }) {
  return (
    <svg width="12" height="12" viewBox="0 0 16 16" fill="none" stroke={active ? C.blue : C.textSecondary}
      strokeWidth="1.5" strokeLinecap="round" style={{ display: 'inline-block', verticalAlign: 'middle', marginLeft: 4 }}>
      <path d="M1.5 3h13M4 8h8M6 13h4" />
    </svg>
  );
}

/* ───── Column Filter Popover ───── */
function ColumnFilter({ col, filterValue, onFilter, data }) {
  const { filterType = 'text' } = col;

  // Always compute uniqueVals to avoid conditional hook call
  const uniqueVals = useMemo(() => {
    if (filterType !== 'select') return [];
    const vals = new Set();
    (data || []).forEach(row => {
      const v = row?.[col.key];
      if (v != null && v !== '') vals.add(String(v));
    });
    return [...vals].sort();
  }, [data, col.key, filterType]);

  if (filterType === 'select') {
    return (
      <div style={{ padding: 8, minWidth: 160 }}>
        <div style={{ fontSize: 11, color: C.textSecondary, marginBottom: 8, fontFamily: body, textTransform: 'uppercase' }}>
          Filter: {col.label}
        </div>
        <select
          value={filterValue || ''}
          onChange={e => onFilter(e.target.value || null)}
          style={{
            width: '100%', padding: '6px 8px', borderRadius: 6,
            border: `1px solid ${C.border}`, background: C.surface2,
            color: C.textPrimary, fontFamily: mono, fontSize: 13,
          }}
        >
          <option value="">All</option>
          {uniqueVals.map(v => <option key={v} value={v}>{v}</option>)}
        </select>
        {filterValue && (
          <button onClick={() => onFilter(null)} style={{
            marginTop: 8, fontSize: 11, color: C.blue, background: 'none',
            border: 'none', cursor: 'pointer', fontFamily: mono, padding: 0,
          }}>Clear</button>
        )}
      </div>
    );
  }

  if (filterType === 'range') {
    const [min, max] = filterValue || ['', ''];
    return (
      <div style={{ padding: 8, minWidth: 160 }}>
        <div style={{ fontSize: 11, color: C.textSecondary, marginBottom: 8, fontFamily: body, textTransform: 'uppercase' }}>
          Filter: {col.label}
        </div>
        <div style={{ display: 'flex', gap: 8 }}>
          <input
            type="number" placeholder="Min" value={min}
            onChange={e => onFilter([e.target.value, max])}
            style={{
              width: '50%', padding: '6px 6px', borderRadius: 6,
              border: `1px solid ${C.border}`, background: C.surface2,
              color: C.textPrimary, fontFamily: mono, fontSize: 13,
            }}
          />
          <input
            type="number" placeholder="Max" value={max}
            onChange={e => onFilter([min, e.target.value])}
            style={{
              width: '50%', padding: '6px 6px', borderRadius: 6,
              border: `1px solid ${C.border}`, background: C.surface2,
              color: C.textPrimary, fontFamily: mono, fontSize: 13,
            }}
          />
        </div>
        {(min || max) && (
          <button onClick={() => onFilter(null)} style={{
            marginTop: 8, fontSize: 11, color: C.blue, background: 'none',
            border: 'none', cursor: 'pointer', fontFamily: mono, padding: 0,
          }}>Clear</button>
        )}
      </div>
    );
  }

  // Default: text filter
  return (
    <div style={{ padding: 8, minWidth: 160 }}>
      <div style={{ fontSize: 11, color: C.textSecondary, marginBottom: 8, fontFamily: body, textTransform: 'uppercase' }}>
        Filter: {col.label}
      </div>
      <input
        type="text" placeholder="Search..." value={filterValue || ''}
        onChange={e => onFilter(e.target.value || null)}
        style={{
          width: '100%', padding: '6px 8px', borderRadius: 6,
          border: `1px solid ${C.border}`, background: C.surface2,
          color: C.textPrimary, fontFamily: mono, fontSize: 13,
        }}
      />
      {filterValue && (
        <button onClick={() => onFilter(null)} style={{
          marginTop: 8, fontSize: 11, color: C.blue, background: 'none',
          border: 'none', cursor: 'pointer', fontFamily: mono, padding: 0,
        }}>Clear</button>
      )}
    </div>
  );
}

/* ═══════════════════════════════════════════════════
   SortableFilterTable
   Extended from GhostDataTable with per-column filters.

   Column config:
   { key, label, width, align, render, mono, sortable, filterable, filterType: 'select'|'range'|'text' }
   ═══════════════════════════════════════════════════ */
export default function SortableFilterTable({
  columns = [],
  data,
  loading = false,
  previousData,
  emptyMessage = 'No data to display',
  onRowClick,
  sortable = true,
  defaultSortKey = null,
  defaultSortDir = 'desc',
}) {
  useEffect(ensureKeyframes, []);

  /* ── Sort state ── */
  const [sortKey, setSortKey] = useState(defaultSortKey);
  const [sortDir, setSortDir] = useState(defaultSortDir);

  /* ── Filter state ── */
  const [filters, setFilters] = useState({});

  const handleSort = (key) => {
    if (!sortable) return;
    const col = columns.find(c => c.key === key);
    if (col && col.sortable === false) return;
    if (sortKey === key) {
      setSortDir(d => d === 'asc' ? 'desc' : 'asc');
    } else {
      setSortKey(key);
      setSortDir('desc');
    }
  };

  const setFilter = (key, value) => {
    setFilters(prev => {
      const next = { ...prev };
      if (value == null || value === '' || (Array.isArray(value) && !value[0] && !value[1])) {
        delete next[key];
      } else {
        next[key] = value;
      }
      return next;
    });
  };

  /* ── Ghost data ── */
  const prevRef = useRef(null);
  useEffect(() => {
    if (data && data.length > 0 && !loading) {
      prevRef.current = data;
    }
  }, [data, loading]);
  const isGhost = loading && !!prevRef.current && prevRef.current.length > 0;
  const rows = isGhost ? prevRef.current : data || [];

  /* ── Apply filters ── */
  const filtered = useMemo(() => {
    if (Object.keys(filters).length === 0) return rows;
    return rows.filter(row => {
      for (const [key, val] of Object.entries(filters)) {
        const cellVal = row?.[key];
        const col = columns.find(c => c.key === key);
        const filterType = col?.filterType || 'text';

        if (filterType === 'select') {
          if (String(cellVal) !== String(val)) return false;
        } else if (filterType === 'range') {
          const [min, max] = val;
          const num = Number(cellVal);
          if (min !== '' && !isNaN(Number(min)) && num < Number(min)) return false;
          if (max !== '' && !isNaN(Number(max)) && num > Number(max)) return false;
        } else {
          // text
          if (cellVal == null) return false;
          if (!String(cellVal).toLowerCase().includes(String(val).toLowerCase())) return false;
        }
      }
      return true;
    });
  }, [rows, filters, columns]);

  /* ── Sort ── */
  const sorted = useMemo(() => {
    if (!sortKey || !filtered.length) return filtered;
    return [...filtered].sort((a, b) => {
      let va = a?.[sortKey];
      let vb = b?.[sortKey];
      if (typeof va === 'string') va = va.toLowerCase();
      if (typeof vb === 'string') vb = vb.toLowerCase();
      if (va == null) return 1;
      if (vb == null) return -1;
      if (va < vb) return sortDir === 'asc' ? -1 : 1;
      if (va > vb) return sortDir === 'asc' ? 1 : -1;
      return 0;
    });
  }, [filtered, sortKey, sortDir]);

  const activeFilterCount = Object.keys(filters).length;

  /* ── Styles ── */
  const thStyle = {
    fontFamily: body, fontSize: 11, fontWeight: 600,
    color: C.textSecondary, textTransform: 'uppercase', letterSpacing: 1,
    padding: '10px 12px', textAlign: 'left',
    borderBottom: `1px solid ${C.border}`, backgroundColor: C.surface,
    position: 'sticky', top: 0, zIndex: 2,
  };
  const tdBase = {
    fontFamily: mono, fontSize: 13, padding: '10px 12px',
    borderBottom: `1px solid ${C.border}`, color: C.textPrimary,
  };
  const ghostRowStyle = { opacity: 1, pointerEvents: 'none', animation: 'sftPulse 2s ease-in-out infinite' };
  const ghostCellOverride = { color: C.textSecondary, opacity: 0.35 };

  /* ── Empty state ── */
  if (!loading && (!rows || rows.length === 0)) {
    return (
      <div style={{
        padding: 48, textAlign: 'center', backgroundColor: C.surface,
        border: `1px solid ${C.border}`, borderRadius: 10,
      }}>
        <div style={{ fontSize: 28, marginBottom: 8, opacity: 0.3, color: C.textSecondary }}>---</div>
        <div style={{ fontFamily: body, fontSize: 14, color: C.textSecondary }}>{emptyMessage}</div>
      </div>
    );
  }

  return (
    <div style={{
      flex: 1, minHeight: 0, backgroundColor: C.surface,
      border: `1px solid ${C.border}`, borderRadius: 10,
      overflow: 'hidden', display: 'flex', flexDirection: 'column',
      transition: 'opacity 0.25s ease',
      opacity: loading && !isGhost ? 0.4 : 1,
    }}>
      {/* Ghost updating badge */}
      {isGhost && (
        <div style={{
          display: 'flex', alignItems: 'center', gap: 8,
          padding: '6px 12px', backgroundColor: `${C.amber}10`,
          borderBottom: `1px solid ${C.border}`,
        }}>
          <span style={{
            display: 'inline-block', width: 6, height: 6, borderRadius: '50%',
            backgroundColor: C.amber, animation: 'sftPulse 1.5s ease-in-out infinite',
          }} />
          <span style={{
            fontFamily: body, fontSize: 11, fontWeight: 600, color: C.amber,
            textTransform: 'uppercase', letterSpacing: 0.5,
          }}>Updating...</span>
        </div>
      )}

      {/* Active filter indicator */}
      {activeFilterCount > 0 && (
        <div style={{
          display: 'flex', alignItems: 'center', gap: 8,
          padding: '6px 12px', backgroundColor: `${C.blue}08`,
          borderBottom: `1px solid ${C.border}`,
        }}>
          <span style={{ fontFamily: body, fontSize: 11, color: C.blue }}>
            {activeFilterCount} filter{activeFilterCount > 1 ? 's' : ''} active
          </span>
          <span style={{ fontFamily: mono, fontSize: 11, color: C.textSecondary }}>
            ({sorted.length} of {rows.length} rows)
          </span>
          <button
            onClick={() => setFilters({})}
            style={{
              marginLeft: 'auto', fontSize: 11, color: C.blue,
              background: 'none', border: 'none', cursor: 'pointer', fontFamily: mono,
            }}
          >Clear all</button>
        </div>
      )}

      <div style={{ flex: 1, minHeight: 0, overflow: 'auto', WebkitOverflowScrolling: 'touch' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', minWidth: columns.length > 5 ? 700 : 'auto' }}>
          <thead>
            <tr>
              {columns.map(col => {
                const isSorted = sortKey === col.key;
                const isFilterable = col.filterable !== false && col.filterType;
                const hasFilter = !!filters[col.key];

                return (
                  <th
                    key={col.key}
                    style={{
                      ...thStyle,
                      width: col.width || 'auto',
                      textAlign: col.align || 'left',
                      cursor: sortable && col.sortable !== false ? 'pointer' : 'default',
                      userSelect: 'none',
                    }}
                  >
                    <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
                      <span onClick={() => handleSort(col.key)} style={{ flex: 1 }}>
                        {col.label}{' '}
                        {isSorted && (
                          <span style={{ fontSize: 10, color: C.blue }}>
                            {sortDir === 'asc' ? '\u25B2' : '\u25BC'}
                          </span>
                        )}
                      </span>
                      {isFilterable && (
                        <Popover.Root>
                          <Popover.Trigger asChild>
                            <button
                              style={{
                                background: 'none', border: 'none', cursor: 'pointer',
                                padding: 4, display: 'flex', alignItems: 'center',
                              }}
                              onClick={e => e.stopPropagation()}
                            >
                              <FilterIcon active={hasFilter} />
                            </button>
                          </Popover.Trigger>
                          <Popover.Portal>
                            <Popover.Content
                              sideOffset={4}
                              style={{
                                background: C.surface, border: `1px solid ${C.border}`,
                                borderRadius: 10, boxShadow: '0 8px 32px rgba(0,0,0,0.4)',
                                zIndex: 100,
                              }}
                            >
                              <ColumnFilter
                                col={col}
                                filterValue={filters[col.key]}
                                onFilter={val => setFilter(col.key, val)}
                                data={rows}
                              />
                            </Popover.Content>
                          </Popover.Portal>
                        </Popover.Root>
                      )}
                    </div>
                  </th>
                );
              })}
            </tr>
          </thead>
          <tbody>
            {sorted.map((row, i) => {
              const rowKey = row?.id || row?.symbol ? `${row.id || row.symbol}-${i}` : i;
              return (
                <tr
                  key={rowKey}
                  style={{
                    cursor: !isGhost && onRowClick ? 'pointer' : 'default',
                    transition: 'background 0.15s',
                    ...(isGhost ? ghostRowStyle : {}),
                  }}
                  onClick={() => { if (!isGhost && onRowClick) onRowClick(row); }}
                  onMouseEnter={e => { if (!isGhost) e.currentTarget.style.backgroundColor = C.surface2; }}
                  onMouseLeave={e => { if (!isGhost) e.currentTarget.style.backgroundColor = 'transparent'; }}
                >
                  {columns.map(col => {
                    const value = row?.[col.key];
                    const rendered = col.render ? col.render(value, row) : value ?? '--';
                    return (
                      <td
                        key={col.key}
                        style={{
                          ...tdBase,
                          textAlign: col.align || 'left',
                          fontFamily: col.mono !== false ? mono : body,
                          ...(isGhost ? ghostCellOverride : {}),
                        }}
                      >
                        {rendered}
                      </td>
                    );
                  })}
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}
